+%% fixture_id: er_stress
+%% purpose: stress test with many entities, relationships, various cardinalities
+erDiagram
+  CUSTOMER ||--o{ ORDER : places
+  CUSTOMER {
+    string name
+    string email
+    int id
+  }
+  ORDER ||--|{ LINE_ITEM : contains
+  ORDER {
+    int id
+    date created
+    string status
+  }
+  LINE_ITEM }|--|| PRODUCT : references
+  LINE_ITEM {
+    int quantity
+    float price
+  }
+  PRODUCT {
+    string name
+    float cost
+    int stock
+  }
+  PRODUCT }o--o{ CATEGORY : "belongs to"
+  CATEGORY {
+    string name
+    string description
+  }
+  CUSTOMER }|--|| ADDRESS : "lives at"
+  ADDRESS {
+    string street
+    string city
+    string zip
+  }
+  ORDER ||--|| PAYMENT : "paid by"
+  PAYMENT {
+    float amount
+    string method
+    date paid
+  }
+  CUSTOMER ||--o{ REVIEW : writes
+  REVIEW }o--|| PRODUCT : about

@@ -0,0 +1,55 @@
+%% fixture_id: requirement_stress
+%% purpose: stress test with many requirements and relationships
+requirementDiagram
+  requirement high_availability {
+    id: REQ-001
+    text: System must maintain 99.99% uptime
+    risk: high
+    verifymethod: analysis
+  }
+  requirement data_encryption {
+    id: REQ-002
+    text: All data must be encrypted at rest and in transit
+    risk: high
+    verifymethod: inspection
+  }
+  requirement response_time {
+    id: REQ-003
+    text: API response time must be under 200ms at p95
+    risk: medium
+    verifymethod: test
+  }
+  requirement audit_logging {
+    id: REQ-004
+    text: All user actions must be logged for audit
+    risk: medium
+    verifymethod: inspection
+  }
+  requirement backup_recovery {
+    id: REQ-005
+    text: System must support point-in-time recovery
+    risk: high
+    verifymethod: demonstration
+  }
+  element load_balancer {
+    type: service
+  }
+  element encryption_module {
+    type: module
+  }
+  element api_gateway {
+    type: service
+  }
+  element audit_service {
+    type: service
+  }
+  element backup_system {
+    type: service
+  }
+  load_balancer - satisfies -> high_availability
+  encryption_module - satisfies -> data_encryption
+  api_gateway - satisfies -> response_time
+  audit_service - satisfies -> audit_logging
+  backup_system - satisfies -> backup_recovery
+  data_encryption - derives -> high_availability
+  audit_logging - refines -> data_encryption
